-- ===========================================================================
-- elearning JTM — Supabase Setup SQL
-- ===========================================================================
-- Run this entire script in: Supabase Dashboard → SQL Editor → New query → Run
-- It creates all 22 tables + indexes and seeds them with dummy data.
-- Idempotent: DROP IF EXISTS at the top makes it safe to re-run.
-- ===========================================================================

BEGIN;

-- ===========================================================================
-- 1. DROP EXISTING (idempotent)
-- ===========================================================================
DROP TABLE IF EXISTS "AIConversation" CASCADE;
DROP TABLE IF EXISTS "AuditLog" CASCADE;
DROP TABLE IF EXISTS "Notification" CASCADE;
DROP TABLE IF EXISTS "UserCompetency" CASCADE;
DROP TABLE IF EXISTS "CourseCompetency" CASCADE;
DROP TABLE IF EXISTS "Competency" CASCADE;
DROP TABLE IF EXISTS "UserBadge" CASCADE;
DROP TABLE IF EXISTS "Badge" CASCADE;
DROP TABLE IF EXISTS "Certificate" CASCADE;
DROP TABLE IF EXISTS "QuizAttempt" CASCADE;
DROP TABLE IF EXISTS "Question" CASCADE;
DROP TABLE IF EXISTS "Quiz" CASCADE;
DROP TABLE IF EXISTS "Progress" CASCADE;
DROP TABLE IF EXISTS "Enrollment" CASCADE;
DROP TABLE IF EXISTS "Content" CASCADE;
DROP TABLE IF EXISTS "Module" CASCADE;
DROP TABLE IF EXISTS "ForumPost" CASCADE;
DROP TABLE IF EXISTS "ForumThread" CASCADE;
DROP TABLE IF EXISTS "Course" CASCADE;
DROP TABLE IF EXISTS "CourseCategory" CASCADE;
DROP TABLE IF EXISTS "User" CASCADE;
DROP TABLE IF EXISTS "Campus" CASCADE;

-- ===========================================================================
-- 2. CREATE TABLES
-- ===========================================================================
CREATE TABLE "Campus" (
  id            TEXT PRIMARY KEY,
  code          TEXT UNIQUE NOT NULL,
  name          TEXT NOT NULL,
  "nameEn"      TEXT,
  state         TEXT NOT NULL,
  region        TEXT NOT NULL,
  address       TEXT,
  phone         TEXT,
  email         TEXT,
  status        TEXT NOT NULL DEFAULT 'active',
  "establishedAt" TEXT,
  metadata      JSONB DEFAULT '{}',
  "createdAt"   TIMESTAMPTZ NOT NULL DEFAULT now(),
  "updatedAt"   TIMESTAMPTZ NOT NULL DEFAULT now()
);
CREATE TABLE "User" (
  id              TEXT PRIMARY KEY,
  email           TEXT UNIQUE NOT NULL,
  name            TEXT NOT NULL,
  "avatarUrl"     TEXT,
  role            TEXT NOT NULL DEFAULT 'pelajar',
  "campusId"      TEXT REFERENCES "Campus"(id) ON DELETE SET NULL,
  "ssoProvider"   TEXT NOT NULL DEFAULT 'mydigital_id',
  "ssoSubject"    TEXT,
  status          TEXT NOT NULL DEFAULT 'active',
  "lastSignInAt"  TIMESTAMPTZ,
  phone           TEXT,
  "icNumber"      TEXT,
  "employeeId"    TEXT,
  "preferredLang" TEXT NOT NULL DEFAULT 'ms',
  metadata        JSONB DEFAULT '{}',
  points          INT NOT NULL DEFAULT 0,
  streak          INT NOT NULL DEFAULT 0,
  "createdAt"     TIMESTAMPTZ NOT NULL DEFAULT now(),
  "updatedAt"     TIMESTAMPTZ NOT NULL DEFAULT now()
);
CREATE TABLE "CourseCategory" (
  id          TEXT PRIMARY KEY,
  name        TEXT NOT NULL,
  "nameEn"    TEXT,
  slug        TEXT UNIQUE NOT NULL,
  icon        TEXT,
  color       TEXT,
  description TEXT,
  "createdAt" TIMESTAMPTZ NOT NULL DEFAULT now()
);
CREATE TABLE "Course" (
  id             TEXT PRIMARY KEY,
  code           TEXT UNIQUE NOT NULL,
  title          TEXT NOT NULL,
  "titleEn"      TEXT,
  description    TEXT NOT NULL,
  "categoryId"   TEXT REFERENCES "CourseCategory"(id) ON DELETE SET NULL,
  "campusId"     TEXT NOT NULL REFERENCES "Campus"(id) ON DELETE RESTRICT,
  "instructorId" TEXT REFERENCES "User"(id) ON DELETE SET NULL,
  level          TEXT NOT NULL DEFAULT 'beginner',
  format         TEXT NOT NULL DEFAULT 'blended',
  "durationHours" INT NOT NULL DEFAULT 0,
  "durationDays"  INT NOT NULL DEFAULT 0,
  credits        INT NOT NULL DEFAULT 0,
  price          DOUBLE PRECISION NOT NULL DEFAULT 0,
  currency       TEXT NOT NULL DEFAULT 'MYR',
  quota          INT NOT NULL DEFAULT 30,
  "enrolledCount" INT NOT NULL DEFAULT 0,
  rating         DOUBLE PRECISION NOT NULL DEFAULT 0,
  "ratingCount"  INT NOT NULL DEFAULT 0,
  "coverColor"   TEXT NOT NULL DEFAULT 'emerald',
  "coverIcon"    TEXT NOT NULL DEFAULT 'book-open',
  tags           JSONB DEFAULT '[]',
  status         TEXT NOT NULL DEFAULT 'published',
  "startDate"    TEXT,
  "endDate"      TEXT,
  "createdAt"    TIMESTAMPTZ NOT NULL DEFAULT now(),
  "updatedAt"    TIMESTAMPTZ NOT NULL DEFAULT now()
);
CREATE TABLE "Module" (
  id          TEXT PRIMARY KEY,
  "courseId"  TEXT NOT NULL REFERENCES "Course"(id) ON DELETE CASCADE,
  title       TEXT NOT NULL,
  description TEXT,
  "order"     INT NOT NULL DEFAULT 0,
  "durationMin" INT NOT NULL DEFAULT 0,
  "isLocked"  BOOLEAN NOT NULL DEFAULT false,
  "createdAt" TIMESTAMPTZ NOT NULL DEFAULT now(),
  "updatedAt" TIMESTAMPTZ NOT NULL DEFAULT now()
);
CREATE TABLE "Content" (
  id              TEXT PRIMARY KEY,
  "moduleId"      TEXT NOT NULL REFERENCES "Module"(id) ON DELETE CASCADE,
  title           TEXT NOT NULL,
  type            TEXT NOT NULL DEFAULT 'video',
  url             TEXT,
  "durationSec"   INT NOT NULL DEFAULT 0,
  "sizeKb"        INT NOT NULL DEFAULT 0,
  description     TEXT,
  "isDownloadable" BOOLEAN NOT NULL DEFAULT true,
  "createdAt"     TIMESTAMPTZ NOT NULL DEFAULT now()
);
CREATE TABLE "Enrollment" (
  id            TEXT PRIMARY KEY,
  "userId"      TEXT NOT NULL REFERENCES "User"(id) ON DELETE CASCADE,
  "courseId"    TEXT NOT NULL REFERENCES "Course"(id) ON DELETE RESTRICT,
  "campusId"    TEXT NOT NULL REFERENCES "Campus"(id) ON DELETE RESTRICT,
  status        TEXT NOT NULL DEFAULT 'active',
  "progressPct" INT NOT NULL DEFAULT 0,
  "enrolledAt"  TIMESTAMPTZ NOT NULL DEFAULT now(),
  "completedAt" TIMESTAMPTZ,
  "finalScore"  DOUBLE PRECISION,
  "createdAt"   TIMESTAMPTZ NOT NULL DEFAULT now(),
  "updatedAt"   TIMESTAMPTZ NOT NULL DEFAULT now()
);
CREATE TABLE "Progress" (
  id              TEXT PRIMARY KEY,
  "enrollmentId"  TEXT NOT NULL REFERENCES "Enrollment"(id) ON DELETE CASCADE,
  "userId"        TEXT NOT NULL REFERENCES "User"(id) ON DELETE CASCADE,
  "contentId"     TEXT NOT NULL REFERENCES "Content"(id) ON DELETE CASCADE,
  status          TEXT NOT NULL DEFAULT 'not_started',
  "timeSpentSec"  INT NOT NULL DEFAULT 0,
  score           DOUBLE PRECISION,
  "completedAt"   TIMESTAMPTZ,
  "updatedAt"     TIMESTAMPTZ NOT NULL DEFAULT now(),
  UNIQUE ("enrollmentId", "contentId")
);
CREATE TABLE "Quiz" (
  id              TEXT PRIMARY KEY,
  "courseId"      TEXT NOT NULL REFERENCES "Course"(id) ON DELETE CASCADE,
  "moduleId"      TEXT,
  title           TEXT NOT NULL,
  description     TEXT,
  "questionCount" INT NOT NULL DEFAULT 0,
  "passMark"      DOUBLE PRECISION NOT NULL DEFAULT 60,
  "timeLimitMin"  INT NOT NULL DEFAULT 30,
  "maxAttempts"   INT NOT NULL DEFAULT 3,
  weight          DOUBLE PRECISION NOT NULL DEFAULT 1,
  "createdAt"     TIMESTAMPTZ NOT NULL DEFAULT now()
);
CREATE TABLE "Question" (
  id              TEXT PRIMARY KEY,
  "quizId"        TEXT NOT NULL REFERENCES "Quiz"(id) ON DELETE CASCADE,
  type            TEXT NOT NULL DEFAULT 'mcq',
  text            TEXT NOT NULL,
  options         JSONB NOT NULL DEFAULT '[]',
  "correctAnswer" JSONB,
  explanation     TEXT,
  marks           DOUBLE PRECISION NOT NULL DEFAULT 1,
  "order"         INT NOT NULL DEFAULT 0
);
CREATE TABLE "QuizAttempt" (
  id              TEXT PRIMARY KEY,
  "quizId"        TEXT NOT NULL REFERENCES "Quiz"(id) ON DELETE RESTRICT,
  "enrollmentId"  TEXT NOT NULL REFERENCES "Enrollment"(id) ON DELETE CASCADE,
  "userId"        TEXT NOT NULL REFERENCES "User"(id) ON DELETE CASCADE,
  answers         JSONB NOT NULL DEFAULT '{}',
  score           DOUBLE PRECISION NOT NULL DEFAULT 0,
  "maxScore"      DOUBLE PRECISION NOT NULL DEFAULT 0,
  percentage      DOUBLE PRECISION NOT NULL DEFAULT 0,
  passed          BOOLEAN NOT NULL DEFAULT false,
  "startedAt"     TIMESTAMPTZ NOT NULL DEFAULT now(),
  "submittedAt"   TIMESTAMPTZ
);
CREATE TABLE "ForumThread" (
  id          TEXT PRIMARY KEY,
  "courseId"  TEXT REFERENCES "Course"(id) ON DELETE SET NULL,
  "userId"    TEXT NOT NULL REFERENCES "User"(id) ON DELETE CASCADE,
  title       TEXT NOT NULL,
  body        TEXT NOT NULL,
  tags        JSONB DEFAULT '[]',
  views       INT NOT NULL DEFAULT 0,
  "isPinned"  BOOLEAN NOT NULL DEFAULT false,
  "isResolved" BOOLEAN NOT NULL DEFAULT false,
  "createdAt" TIMESTAMPTZ NOT NULL DEFAULT now(),
  "updatedAt" TIMESTAMPTZ NOT NULL DEFAULT now()
);
CREATE TABLE "ForumPost" (
  id          TEXT PRIMARY KEY,
  "threadId"  TEXT NOT NULL REFERENCES "ForumThread"(id) ON DELETE CASCADE,
  "userId"    TEXT NOT NULL REFERENCES "User"(id) ON DELETE CASCADE,
  body        TEXT NOT NULL,
  likes       INT NOT NULL DEFAULT 0,
  "isAnswer"  BOOLEAN NOT NULL DEFAULT false,
  "createdAt" TIMESTAMPTZ NOT NULL DEFAULT now(),
  "updatedAt" TIMESTAMPTZ NOT NULL DEFAULT now()
);
CREATE TABLE "Certificate" (
  id              TEXT PRIMARY KEY,
  "certNumber"    TEXT UNIQUE NOT NULL,
  "userId"        TEXT NOT NULL REFERENCES "User"(id) ON DELETE RESTRICT,
  "courseId"      TEXT NOT NULL REFERENCES "Course"(id) ON DELETE RESTRICT,
  "campusId"      TEXT NOT NULL REFERENCES "Campus"(id) ON DELETE RESTRICT,
  "enrollmentId"  TEXT UNIQUE NOT NULL REFERENCES "Enrollment"(id) ON DELETE RESTRICT,
  "verifyCode"    TEXT UNIQUE NOT NULL,
  title           TEXT NOT NULL,
  "recipientName" TEXT NOT NULL,
  "recipientIc"   TEXT,
  score           DOUBLE PRECISION NOT NULL,
  grade           TEXT NOT NULL,
  "issuedAt"      TIMESTAMPTZ NOT NULL DEFAULT now(),
  "expiryAt"      TIMESTAMPTZ,
  status          TEXT NOT NULL DEFAULT 'valid',
  signature       TEXT NOT NULL DEFAULT 'Jabatan Tenaga Manusia (JTM)',
  "createdAt"     TIMESTAMPTZ NOT NULL DEFAULT now()
);
CREATE TABLE "Badge" (
  id          TEXT PRIMARY KEY,
  code        TEXT UNIQUE NOT NULL,
  name        TEXT NOT NULL,
  "nameEn"    TEXT,
  description TEXT NOT NULL,
  icon        TEXT NOT NULL DEFAULT 'award',
  color       TEXT NOT NULL DEFAULT 'amber',
  criteria    JSONB NOT NULL,
  issuer      TEXT NOT NULL DEFAULT 'Jabatan Tenaga Manusia',
  "createdAt" TIMESTAMPTZ NOT NULL DEFAULT now()
);
CREATE TABLE "UserBadge" (
  id         TEXT PRIMARY KEY,
  "userId"   TEXT NOT NULL REFERENCES "User"(id) ON DELETE CASCADE,
  "badgeId"  TEXT NOT NULL REFERENCES "Badge"(id) ON DELETE RESTRICT,
  "awardedAt" TIMESTAMPTZ NOT NULL DEFAULT now(),
  evidence   JSONB,
  UNIQUE ("userId", "badgeId")
);
CREATE TABLE "Competency" (
  id          TEXT PRIMARY KEY,
  code        TEXT UNIQUE NOT NULL,
  name        TEXT NOT NULL,
  "nameEn"    TEXT,
  framework   TEXT NOT NULL DEFAULT 'SKM',
  level       INT NOT NULL DEFAULT 1,
  sector      TEXT,
  description TEXT,
  "createdAt" TIMESTAMPTZ NOT NULL DEFAULT now()
);
CREATE TABLE "CourseCompetency" (
  id              TEXT PRIMARY KEY,
  "courseId"      TEXT NOT NULL REFERENCES "Course"(id) ON DELETE CASCADE,
  "competencyId"  TEXT NOT NULL REFERENCES "Competency"(id) ON DELETE CASCADE,
  weight          DOUBLE PRECISION NOT NULL DEFAULT 1,
  UNIQUE ("courseId", "competencyId")
);
CREATE TABLE "UserCompetency" (
  id              TEXT PRIMARY KEY,
  "userId"        TEXT NOT NULL REFERENCES "User"(id) ON DELETE CASCADE,
  "competencyId"  TEXT NOT NULL REFERENCES "Competency"(id) ON DELETE CASCADE,
  status          TEXT NOT NULL DEFAULT 'in_progress',
  "achievedAt"    TIMESTAMPTZ,
  evidence        JSONB,
  "createdAt"     TIMESTAMPTZ NOT NULL DEFAULT now(),
  "updatedAt"     TIMESTAMPTZ NOT NULL DEFAULT now(),
  UNIQUE ("userId", "competencyId")
);
CREATE TABLE "Notification" (
  id        TEXT PRIMARY KEY,
  "userId"  TEXT NOT NULL REFERENCES "User"(id) ON DELETE CASCADE,
  type      TEXT NOT NULL DEFAULT 'info',
  title     TEXT NOT NULL,
  message   TEXT NOT NULL,
  link      TEXT,
  read      BOOLEAN NOT NULL DEFAULT false,
  "createdAt" TIMESTAMPTZ NOT NULL DEFAULT now()
);
CREATE TABLE "AuditLog" (
  id        TEXT PRIMARY KEY,
  "userId"  TEXT REFERENCES "User"(id) ON DELETE SET NULL,
  "campusId" TEXT REFERENCES "Campus"(id) ON DELETE SET NULL,
  action    TEXT NOT NULL,
  entity    TEXT,
  "entityId" TEXT,
  details   JSONB DEFAULT '{}',
  ip        TEXT,
  "createdAt" TIMESTAMPTZ NOT NULL DEFAULT now()
);
CREATE TABLE "AIConversation" (
  id        TEXT PRIMARY KEY,
  "userId"  TEXT NOT NULL REFERENCES "User"(id) ON DELETE CASCADE,
  "courseId" TEXT,
  title     TEXT,
  messages  JSONB NOT NULL DEFAULT '[]',
  "createdAt" TIMESTAMPTZ NOT NULL DEFAULT now(),
  "updatedAt" TIMESTAMPTZ NOT NULL DEFAULT now()
);

-- Indexes for common queries
CREATE INDEX "idx_User_campusId" ON "User" ("campusId");
CREATE INDEX "idx_User_role" ON "User" (role);
CREATE INDEX "idx_Course_campusId" ON "Course" ("campusId");
CREATE INDEX "idx_Course_categoryId" ON "Course" ("categoryId");
CREATE INDEX "idx_Course_status" ON "Course" (status);
CREATE INDEX "idx_Enrollment_userId" ON "Enrollment" ("userId");
CREATE INDEX "idx_Enrollment_courseId" ON "Enrollment" ("courseId");
CREATE INDEX "idx_Enrollment_campusId" ON "Enrollment" ("campusId");
CREATE INDEX "idx_Progress_enrollmentId" ON "Progress" ("enrollmentId");
CREATE INDEX "idx_Progress_userId" ON "Progress" ("userId");
CREATE INDEX "idx_Certificate_userId" ON "Certificate" ("userId");
CREATE INDEX "idx_ForumThread_courseId" ON "ForumThread" ("courseId");
CREATE INDEX "idx_ForumPost_threadId" ON "ForumPost" ("threadId");
CREATE INDEX "idx_Notification_userId" ON "Notification" ("userId");
CREATE INDEX "idx_AuditLog_campusId" ON "AuditLog" ("campusId");
CREATE INDEX "idx_AIConversation_userId" ON "AIConversation" ("userId");

-- ===========================================================================
-- 3. SEED DATA
-- ===========================================================================
