SELECT gen_random_uuid()::text, 'seed_000000nw_pt9f48', 'seed_0000002u_e2x8i9', c.id,
  CASE WHEN 75 = 0 THEN 'not_started' WHEN random() < 75/100.0 THEN 'completed' ELSE 'in_progress' END,
  floor(60 + random()*1740)::int,
  floor(70 + random()*30)::int,
  CASE WHEN random() < 75/100.0 THEN now() ELSE NULL END, now()
FROM "Content" c JOIN "Module" m ON c."moduleId" = m.id WHERE m."courseId" = 'seed_000000g6_15pmzzp' LIMIT 5;
